arguments.file_text:
namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public string ImageUrl { get; set; } = string.Empty;
    public int TotalRatingPoints { get; set; }
    public int RatingCount { get; set; }

    public double AverageRating => RatingCount > 0 ? (double)TotalRatingPoints / RatingCount : 0;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
                Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.",
                TotalRatingPoints = 14, RatingCount = 3 },

            new() { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Ingredients = "Spaghetti\nGuanciale (or pancetta)\nEggs\nPecorino Romano\nBlack pepper",
                Steps = "1. Cook spaghetti in salted boiling water until al dente.\n2. Crisp guanciale in a pan over medium heat.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale, then quickly mix in egg mixture off heat.\n5. Serve immediately with extra pecorino.",
                TotalRatingPoints = 9, RatingCount = 2 },

            new() { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nTomato sauce\nHeavy cream\nGarlic\nGinger\nOnion",
                Steps = "1. Marinate chicken in yogurt, garam masala, turmeric, and cumin for 1 hour.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger. Add tomato sauce and cream.\n4. Simmer sauce 15 minutes, add chicken pieces.\n5. Serve over basmati rice with naan bread.",
                TotalRatingPoints = 10, RatingCount = 2 },

            new() { Id = 4, Title = "Vegetable Biryani", Category = "Indian",
                Ingredients = "Basmati rice\nMixed vegetables\nOnions\nYogurt\nBiryani masala\nSaffron\nMint\nCilantro\nGhee",
                Steps = "1. Soak basmati rice for 30 minutes, then parboil.\n2. Sauté sliced onions until golden in ghee.\n3. Layer vegetables, rice, fried onions, herbs, and saffron milk.\n4. Cover tightly and cook on low heat for 25 minutes.\n5. Gently fluff and serve with raita.",
                TotalRatingPoints = 5, RatingCount = 1 },

            new() { Id = 5, Title = "Tacos Al Pastor", Category = "Mexican",
                Ingredients = "Pork shoulder\nPineapple\nChili peppers\nAchiote paste\nCorn tortillas\nOnion\nCilantro\nLime",
                Steps = "1. Blend chili peppers and achiote paste into a marinade.\n2. Coat sliced pork and marinate for 4 hours.\n3. Grill pork and pineapple until caramelized.\n4. Chop pork and pineapple into small pieces.\n5. Serve on warm tortillas with onion, cilantro, and lime.",
                TotalRatingPoints = 15, RatingCount = 3 },

            new() { Id = 6, Title = "Guacamole", Category = "Mexican",
                Ingredients = "Avocados\nLime juice\nCilantro\nOnion\nTomato\nJalapeño\nSalt\nGarlic",
                Steps = "1. Halve avocados and remove pits.\n2. Mash avocado to desired consistency.\n3. Fold in diced onion, tomato, jalapeño, and cilantro.\n4. Season with lime juice, garlic, and salt.\n5. Serve immediately with tortilla chips.",
                TotalRatingPoints = 8, RatingCount = 2 },

            new() { Id = 7, Title = "Chocolate Lava Cake", Category = "Desserts",
                Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract",
                Steps = "1. Preheat oven to 425°F (220°C). Grease ramekins.\n2. Melt chocolate and butter together.\n3. Whisk eggs and sugar until thick, fold into chocolate mixture.\n4. Add flour and vanilla, mix gently.\n5. Pour into ramekins and bake for 12-14 minutes.\n6. Invert onto plates and serve immediately.",
                TotalRatingPoints = 5, RatingCount = 1 },

            new() { Id = 8, Title = "Miso Soup", Category = "Japanese",
                Ingredients = "Dashi stock\nMiso paste\nTofu\nWakame seaweed\nGreen onions",
                Steps = "1. Bring dashi stock to a gentle simmer.\n2. Dissolve miso paste into the broth (do not boil).\n3. Add cubed tofu and rehydrated wakame.\n4. Simmer for 2 minutes.\n5. Garnish with sliced green onions and serve.",
                TotalRatingPoints = 4, RatingCount = 1 },

            new() { Id = 9, Title = "Teriyaki Salmon", Category = "Japanese",
                Ingredients = "Salmon fillets\nSoy sauce\nMirin\nSake\nSugar\nGinger\nSesame seeds\nSteamed rice",
                Steps = "1. Combine soy sauce, mirin, sake, and sugar for teriyaki glaze.\n2. Sear salmon skin-side down for 4 minutes.\n3. Flip and pour glaze over salmon.\n4. Cook 3-4 more minutes, basting with glaze.\n5. Serve over rice, garnished with sesame seeds.",
                TotalRatingPoints = 9, RatingCount = 2 },
        };
        _nextId = 10;
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            recipe.TotalRatingPoints += stars;
            recipe.RatingCount++;
        }
    }

    public Recipe AddRecipe(RecipeSubmission submission)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public string ImageUrl { get; set; } = string.Empty;
