@page "/category/{CategoryName}"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (recipes is null || recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="text-muted mb-2">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-outline-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeHub.Models.Recipe>? recipes;

    protected override void OnInitialized()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{RecipeId:int}"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeHub</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
    <a href="/" class="btn btn-outline-secondary">← Back to Home</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @recipe.Category</p>

    <div class="card mb-4">
        <div class="card-body">
            <h3>📋 Ingredients</h3>
            <ul class="list-group list-group-flush">
                @foreach (var ingredient in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                {
                    <li class="list-group-item">@ingredient</li>
                }
            </ul>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h3>👨‍🍳 Steps</h3>
            @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
            {
                <p>@step</p>
            }
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h3>⭐ Rate This Recipe</h3>
            <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />
        </div>
    </div>

    <a href="category/@recipe.Category" class="btn btn-outline-secondary">← Back to @recipe.Category Recipes</a>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private RecipeHub.Models.Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetById(RecipeId);
    }
}

@rendermode InteractiveServer
@inject RecipeHub.Services.RecipeService RecipeService

@if (submitted)
{
    <div class="alert alert-success">
        Thank you! You rated this recipe @selectedRating star(s).
    </div>
}

<div class="d-flex align-items-center gap-2">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-3 text-decoration-none"
                style="cursor: pointer; color: @(star <= (hoverRating > 0 ? hoverRating : selectedRating) ? "#ffc107" : "#dee2e6")"
                @onclick="() => SubmitRating(star)"
                @onmouseover="() => hoverRating = star"
                @onmouseout="() => hoverRating = 0"
                disabled="@submitted"
                title="Rate @star star(s)">
            ★
        </button>
    }
    @if (selectedRating > 0)
    {
        <span class="text-muted ms-2">@selectedRating / 5</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int selectedRating;
    private int hoverRating;
    private bool submitted;

    private void SubmitRating(int stars)
    {
        if (submitted) return;
        selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeHub.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (!string.IsNullOrEmpty(successMessage))
{
    <div class="alert alert-success">@successMessage</div>
}

<EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="submission.Title"
                   placeholder="e.g., Grandma's Apple Pie" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="submission.Category">
            <option value="">-- Select a category --</option>
            @foreach (var cat in RecipeService.GetCategories())
            {
                <option value="@cat">@cat</option>
            }
            <option value="Other">Other</option>
        </InputSelect>
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" rows="6"
                       @bind-Value="submission.Ingredients"
                       placeholder="2 cups flour&#10;1 cup sugar&#10;3 large apples..." />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Preparation Steps</label>
        <InputTextArea id="steps" class="form-control" rows="6"
                       @bind-Value="submission.Steps"
                       placeholder="1. Preheat oven to 350°F...&#10;2. Mix dry ingredients..." />
    </div>

    <button type="submit" class="btn btn-success"
            disabled="@(string.IsNullOrWhiteSpace(submission.Title) || string.IsNullOrWhiteSpace(submission.Category))">
        Submit Recipe
    </button>
    <a href="/" class="btn btn-outline-secondary ms-2">Cancel</a>
</EditForm>

@code {
    private RecipeHub.Models.RecipeSubmission submission = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(submission.Title) || string.IsNullOrWhiteSpace(submission.Category))
            return;

        var recipe = RecipeService.AddRecipe(submission);
        successMessage = $"'{recipe.Title}' has been submitted successfully!";
        submission = new();
    }
}

